UPDATE ar_report SET uploaded_file_path = #{path}, update_by = #{updateBy}, update_time = CURRENT_TIMESTAMP WHERE id = #{id} AND deleted = 0
AND uploaded_file_path IS NULL
AND uploaded_file_path = #{expectedOldPath}

mapper.select:
SELECT r.id, r.enterprise_id, r.audit_year, r.report_name, r.report_type, r.status, r.generated_file_path, r.uploaded_file_path, r.uploaded_file_size, r.uploaded_file_name, r.uploaded_at, r.generate_time, r.submit_time, r.template_id, r.submission_id, r.flow_chart_path, r.review_comment, r.reviewer_id, r.create_by, r.create_time, r.update_by, r.update_time, r.deleted, e.enterprise_name FROM ar_report r LEFT JOIN ent_enterprise e ON e.id = r.enterprise_id WHERE r.enterprise_id = #{enterpriseId} AND r.deleted = 0
AND r.audit_year = #{auditYear}
ORDER BY r.create_time DESC

SELECT r.id, r.enterprise_id, r.audit_year, r.report_name, r.report_type, r.status, r.generated_file_path, r.uploaded_file_path, r.uploaded_file_size, r.uploaded_file_name, r.uploaded_at, r.generate_time, r.submit_time, r.template_id, r.submission_id, r.flow_chart_path, r.review_comment, r.reviewer_id, r.create_by, r.create_time, r.update_by, r.update_time, r.deleted, e.enterprise_name FROM ar_report r LEFT JOIN ent_enterprise e ON e.id = r.enterprise_id WHERE r.deleted = 0
AND r.status = #{status}
AND r.audit_year = #{auditYear}
ORDER BY r.submit_time DESC, r.update_time DESC
